questionvariables.text:
/* ===== Randomised parameters ===== */
N_val:  rand([200, 500, 1000]);
lc_val: rand([0.2, 0.3, 0.4]);
lg_val: rand([5e-4, 1e-3, 2e-3]);
Ac_val: rand([4e-4, 9e-4, 16e-4]);
mur_val: rand([500, 1000, 2000]);
mu0: 4*%pi/10^7;

/* Aliases so students can type symbolic names from the hints */
lc: lc_val;
lg: lg_val;
Ac: Ac_val;
mur: mur_val;
N: N_val;

/* ===== Reluctances (symbolic and numerical) ===== */
ta_Rc_sym: lc_val/(mur_val*mu0*Ac_val);
ta_Rg_sym: lg_val/(mu0*Ac_val);
ta_Rc: float(ta_Rc_sym);
ta_Rg: float(ta_Rg_sym);
ta_Rt: float(ta_Rc + ta_Rg);

/* ===== Inductance ===== */
ta_L: float(N_val^2 / ta_Rt);

/* ===== Sensitivity: dL/dlg ===== */
/* L = N^2 / (lc/(mur*mu0*Ac) + lg/(mu0*Ac))                        */
/* Let D = lc/(mur*mu0*Ac) + lg/(mu0*Ac). Then L = N^2/D.            */
/* dD/dlg = 1/(mu0*Ac). dL/dlg = -N^2/D^2 * (1/(mu0*Ac))            */
/* = -N^2*mu0*Ac / (lc/mur + lg)^2                                    */
ta_dLdlg_sym: -N_val^2*mu0*Ac_val / (lc_val/mur_val + lg_val)^2;
ta_dLdlg: float(ta_dLdlg_sym);

/* ===== Percentage change for 10% increase in lg ===== */
delta_lg: 0.1*lg_val;
ta_pct: float(ta_dLdlg * delta_lg / ta_L * 100);

/* ===== MCQ option lists (STACK dropdown format) ===== */
ta_analogy: 1;
ta_dominator: if ta_Rg > ta_Rc then 1 else 2;
ta_design_reason: 1;

mcq_analogy: [[1, true, "MMF (NI) <-> Voltage; Reluctance <-> Resistance; Flux <-> Current"],
              [2, false, "MMF (NI) <-> Current; Reluctance <-> Conductance; Flux <-> Voltage"],
              [3, false, "MMF (NI) <-> Power; Reluctance <-> Impedance; Flux <-> Energy"]];

mcq_design: [[1, true, "The air gap increases reluctance, reducing L, but prevents core saturation at high currents"],
             [2, false, "The air gap reduces eddy current losses; the inductance drop is a side effect"]];

/* ===== Teacher answers for each input ===== */
ta1: mcq_analogy;
ta2: ta_Rc_sym;
ta3: ta_Rg_sym;
ta4: ta_Rt;
ta5: ta_L;
ta6: ta_dLdlg_sym;
ta7: ta_pct;
ta8: mcq_design;

/* Explicit correct values for PRT comparison (MCQ lists fail with AlgEquiv) */
ta1_correct: 1;
ta8_correct: 1;

feedbackvariables.text:
/* Check for order-of-magnitude error (10x or 0.1x) */
sa2_float: float(ans2);
prt2_oom_ok: if (abs(sa2_float) > 0) then (
  is(abs(sa2_float/ta_Rc - 10) / 10 < 0.05) or is(abs(sa2_float/ta_Rc - 1/10) / (1/10) < 0.05)
) else false;

/* Check for order-of-magnitude error (10x or 0.1x) */
sa3_float: float(ans3);
prt3_oom_ok: if (abs(sa3_float) > 0) then (
  is(abs(sa3_float/ta_Rg - 10) / 10 < 0.05) or is(abs(sa3_float/ta_Rg - 1/10) / (1/10) < 0.05)
) else false;

/* Check for order-of-magnitude error (10x or 0.1x) */
sa4_float: float(ans4);
ref4_float: float(ta4);
prt4_oom_ok: if (abs(sa4_float) > 0 and abs(ref4_float) > 0) then (
  is(abs(sa4_float/ref4_float - 10) / 10 < 0.05) or is(abs(sa4_float/ref4_float - 1/10) / (1/10) < 0.05)
) else false;

/* Check for order-of-magnitude error (10x or 0.1x) */
sa5_float: float(ans5);
ref5_float: float(ta5);
prt5_oom_ok: if (abs(sa5_float) > 0 and abs(ref5_float) > 0) then (
  is(abs(sa5_float/ref5_float - 10) / 10 < 0.05) or is(abs(sa5_float/ref5_float - 1/10) / (1/10) < 0.05)
) else false;

/* Check for order-of-magnitude error (10x or 0.1x) */
sa6_float: float(ans6);
ref6_float: float(ta_dLdlg);
prt6_oom_ok: if (abs(sa6_float) > 0 and abs(ref6_float) > 0) then (
  is(abs(sa6_float/ref6_float - 10) / 10 < 0.05) or is(abs(sa6_float/ref6_float - 1/10) / (1/10) < 0.05)
) else false;

sa7_float: float(ans7);
ref7_float: float(ta7);
prt7_oom_ok: if (abs(ref7_float) > 1.0e-30 and abs(sa7_float) > 1.0e-30 and (abs(sa7_float/ref7_float - 10) < 1.5 or abs(sa7_float/ref7_float - 0.1) < 0.015)) then true else false;
